#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *A = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d", &A[i]);
        for(int i=0;i<N;i+=3){
            int val = A[i];
            if(i+1<N) A[i+1]=val;
            if(i+2<N) A[i+2]=val;
        }
        for(int i=0;i<N;i++){
            if(i) printf(" ");
            printf("%d", A[i]);
        }
        printf("\n");
        free(A);
    }
    return 0;
}

