#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        i = 0
        while i < N:
            val = a[i]
            if i + 1 < N:
                a[i + 1] = val
            if i + 2 < N:
                a[i + 2] = val
            i += 3
        out_lines.append(' '.join(map(str, a)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

